import React, { useState, useEffect } from 'react';
import { salvarHistoricoNoStorage, carregarHistoricoDoStorage } from '../utils/localStorageHistorico';
import MenuLateral from '../components/MenuLateral';
import { Link, useLocation } from 'react-router-dom';

export default function EnlacesContratadosPage() {
  // ...lógica e states permanecem iguais...

  // Recupera info do cliente do localStorage (apenas para exibir)
  const [clienteInfo, setClienteInfo] = useState(null);
  const location = useLocation();
  const [clienteSelecionado, setClienteSelecionado] = useState({ cnpj: 'semcnpj' });
  useEffect(() => {
    try {
      const salvo = localStorage.getItem('clienteSelecionado');
      if (salvo) {
        const obj = JSON.parse(salvo);
        if (obj.cnpj) {
          setClienteSelecionado(obj);
          return;
        }
      }
    } catch {}
    setClienteSelecionado({ cnpj: 'semcnpj' });
  }, [location]);
  useEffect(() => {
    if (clienteSelecionado && clienteSelecionado.razaoSocial && clienteSelecionado.cnpj) {
      setClienteInfo(
        <div style={{marginBottom: 16, textAlign: 'center'}}>
          <div style={{fontWeight:700, fontSize: '1.1rem', color: '#fff'}}>{clienteSelecionado.razaoSocial}</div>
          <div style={{fontWeight:500, fontSize: '0.95rem', color: '#fff'}}>CNPJ: {clienteSelecionado.cnpj}</div>
        </div>
      );
    } else {
      setClienteInfo(null);
    }
  }, [clienteSelecionado]);

  // ...restante da lógica do componente (states, funções, etc)...

  return (
    <div style={{ display: 'flex' }}>
      <MenuLateral voltarLink={<a href="/" style={{textDecoration:'none',color:'#1976d2',fontWeight:'bold',fontSize:'1.1rem',display:'block',marginBottom:'1.5rem',marginTop:'1rem'}}>&larr; Voltar</a>} clienteInfo={clienteInfo} />
      <div style={{marginLeft:200, flex:1, minHeight:'100vh', background:'#f8f9fb', padding:'2rem'}}>
        <div style={{ flex: 1, padding: '40px 0', display: 'flex', flexDirection: 'column', alignItems: 'flex-start' }}>
          {/* Abrindo fragmento para envolver ambos os blocos */}
          <>
            <h2 style={{ color: '#1976d2', marginBottom: 24 }}>Enlaces Contratados</h2>
            <div style={{ background: '#fff', borderRadius: 12, boxShadow: '0 2px 8px #0001', padding: 32, maxWidth: 400, width: '100%', marginBottom: 32 }}>
              <div style={{ marginBottom: 24 }}>
                <label style={{ fontWeight: 600 }}>
                  Ano
                  <select value={ano} onChange={e => { setAno(e.target.value); localStorage.setItem('enlacesContratadosForm', JSON.stringify({ ano: e.target.value, origem, destino, idEnlace, meio, cnpj })); }} style={{ width: '100%', marginTop: 4, padding: 8, borderRadius: 4, border: '1px solid #ccc' }}>
                    <option value="2024">2024</option>
                    <option value="2025">2025</option>
                    <option value="2026">2026</option>
                  </select>
                </label>
              </div>
              <div style={{ marginBottom: 24 }}>
                <label style={{ fontWeight: 600, display: 'block', marginBottom: 6 }}>
                  Estação de Origem (ID)
                  <input
                    type="text"
                    placeholder="O código de identificação da estação de onde parte o sinal."
                    value={origem}
                    onChange={e => { setOrigem(e.target.value); localStorage.setItem('enlacesContratadosForm', JSON.stringify({ ano, origem: e.target.value, destino, idEnlace, meio, cnpj })); }}
                    style={{ width: '100%', marginTop: 4, padding: 8, borderRadius: 4, border: '1px solid #ccc', fontStyle: 'italic' }}
                  />
                </label>
              </div>
              <div style={{ marginBottom: 24 }}>
                <label style={{ fontWeight: 600, display: 'block', marginBottom: 6 }}>
                  Estação de Destino (ID)
                  <input
                    type="text"
                    placeholder="O código de identificação da estação onde chega o sinal."
                    value={destino}
                    onChange={e => { setDestino(e.target.value); localStorage.setItem('enlacesContratadosForm', JSON.stringify({ ano, origem, destino: e.target.value, idEnlace, meio, cnpj })); }}
                    style={{ width: '100%', marginTop: 4, padding: 8, borderRadius: 4, border: '1px solid #ccc', fontStyle: 'italic' }}
                  />
                </label>
              </div>
              <div style={{ marginBottom: 24 }}>
                <label style={{ fontWeight: 600, display: 'block', marginBottom: 6 }}>
                  Identificação do Link (ID Enlace)
                  <input
                    type="text"
                    placeholder="O código único desse circuito/link. Atenção: Não repita códigos no mesmo arquivo."
                    value={idEnlace}
                    onChange={e => { setIdEnlace(e.target.value); localStorage.setItem('enlacesContratadosForm', JSON.stringify({ ano, origem, destino, idEnlace: e.target.value, meio, cnpj })); }}
                    style={{ width: '100%', marginTop: 4, padding: 8, borderRadius: 4, border: '1px solid #ccc', fontStyle: 'italic' }}
                  />
                </label>
              </div>
              <div style={{ marginBottom: 24 }}>
                <label style={{ fontWeight: 600, display: 'block', marginBottom: 6 }}>
                  Meio de Transporte
                  <input
                    type="text"
                    placeholder="Como o sinal é transmitido (Ex: Fibra Óptica, Rádio, Satélite)."
                    value={meio}
                    onChange={e => { setMeio(e.target.value); localStorage.setItem('enlacesContratadosForm', JSON.stringify({ ano, origem, destino, idEnlace, meio: e.target.value, cnpj })); }}
                    style={{ width: '100%', marginTop: 4, padding: 8, borderRadius: 4, border: '1px solid #ccc', fontStyle: 'italic' }}
                  />
                </label>
              </div>
              <div style={{ marginBottom: 24 }}>
                <label style={{ fontWeight: 600, display: 'block', marginBottom: 6 }}>
                  CNPJ da Fornecedora
                  <input
                    type="text"
                    placeholder="Se o link for contratado de terceiros, informe o CNPJ da empresa fornecedora"
                    value={cnpj}
                    onChange={handleCnpjChange}
                    maxLength={18}
                    style={{ width: '100%', marginTop: 4, padding: 8, borderRadius: 4, border: '1px solid #ccc', fontStyle: 'italic', fontFamily: 'monospace' }}
                    inputMode="numeric"
                    pattern="\d{2}\.\d{3}\.\d{3}/\d{4}-\d{2}"
                  />
                </label>
              </div>
              <button
                type="button"
                onClick={handleSalvarLinha}
                style={{
                  width: '100%',
                  padding: '12px',
                  background: '#1976d2',
                  color: '#fff',
                  border: 'none',
                  borderRadius: 6,
                  fontWeight: 700,
                  fontSize: 16,
                  cursor: 'pointer',
                  marginTop: 8
                }}
              >
                Salvar linha
              </button>
              {linhas.length > 0 && (
                <div style={{ marginTop: 32 }}>
                  <h3 style={{ fontSize: 18, marginBottom: 12 }}>Linhas salvas</h3>
                  <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
                    <thead>
                      <tr style={{ background: '#f4f6fa' }}>
                        <th style={{ border: '1px solid #ccc', padding: 6 }}>Ano</th>
                        <th style={{ border: '1px solid #ccc', padding: 6 }}>Origem</th>
                        <th style={{ border: '1px solid #ccc', padding: 6 }}>Destino</th>
                        <th style={{ border: '1px solid #ccc', padding: 6 }}>ID Enlace</th>
                        <th style={{ border: '1px solid #ccc', padding: 6 }}>Meio</th>
                        <th style={{ border: '1px solid #ccc', padding: 6 }}>CNPJ</th>
                      </tr>
                    </thead>
                    <tbody>
                      {linhas.map((linha, idx) => (
                        <tr key={idx}>
                          <td style={{ border: '1px solid #ccc', padding: 6 }}>{linha.ano}</td>
                          <td style={{ border: '1px solid #ccc', padding: 6 }}>{linha.origem}</td>
                          <td style={{ border: '1px solid #ccc', padding: 6 }}>{linha.destino}</td>
                          <td style={{ border: '1px solid #ccc', padding: 6 }}>{linha.idEnlace}</td>
                          <td style={{ border: '1px solid #ccc', padding: 6 }}>{linha.meio}</td>
                          <td style={{ border: '1px solid #ccc', padding: 6 }}>{linha.cnpj}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                  <button
                    type="button"
                    onClick={gerarCSV}
                    style={{
                      width: '100%',
                      padding: '12px',
                      background: '#388e3c',
                      color: '#fff',
                      border: 'none',
                      borderRadius: 6,
                      fontWeight: 700,
                      fontSize: 16,
                      cursor: 'pointer',
                      marginTop: 16
                    }}
                  >
                    Gerar CSV
                  </button>
                </div>
              )}
            </div>
            {/* HISTÓRICO ABAIXO À ESQUERDA, PADRÃO DOS OUTROS MENUS */}
            <div style={{ marginTop: 0, maxWidth: 500 }}>
              <h3 style={{ fontSize: 18, marginBottom: 12, color: '#1976d2' }}>Histórico de arquivos gerados</h3>
              {historicoArquivos && historicoArquivos.length === 0 ? (
                <div style={{ color: '#888', fontStyle: 'italic', fontSize: 14, padding: 8, background: '#f9f9f9', borderRadius: 6 }}>
                  Nenhum arquivo gerado ainda.
                </div>
              ) : (
                <ul style={{ paddingLeft: 0, listStyle: 'none' }}>
                  {historicoArquivos && historicoArquivos.map((arq, idx) => (
                    <li key={idx} style={{ marginBottom: 6, fontSize: 15, display: 'flex', alignItems: 'center', gap: 12 }}>
                      <span style={{ fontWeight: 500 }}>
                        {arq.nome} <span style={{ color: '#888', fontSize: 13 }}>({arq.data})</span>
                      </span>
                      <button
                        style={{ background: '#1976d2', color: '#fff', border: 'none', borderRadius: 3, padding: '2px 10px', fontSize: 13, cursor: 'pointer', marginLeft: 4 }}
                        title="Baixar este CSV"
                        onClick={() => {
                          const blob = new Blob([arq.conteudo], { type: 'text/csv;charset=utf-8;' });
                          const url = URL.createObjectURL(blob);
                          const link = document.createElement('a');
                          link.href = url;
                          link.setAttribute('download', arq.nome);
                          document.body.appendChild(link);
                          link.click();
                          document.body.removeChild(link);
                          URL.revokeObjectURL(url);
                        }}
                      >Baixar</button>
                      <button
                        style={{ background: '#e53935', color: '#fff', border: 'none', borderRadius: 3, padding: '2px 10px', fontSize: 13, cursor: 'pointer' }}
                        title="Excluir este CSV do histórico"
                        onClick={() => {
                          setHistoricoArquivos(prev => {
                            const novo = prev.filter((_, i) => i !== idx);
                            salvarHistoricoNoStorage(novo, clienteSelecionado.cnpj);
                            return novo;
                          });
                        }}
                      >Excluir</button>
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </>
        </div>
      </div>
    </div>
  );
}
